import{_ as a,o as i,c as t,ae as e}from"./chunks/framework.BEtfQoF7.js";const k=JSON.parse('{"title":"Claude Code 프로그래밍 방식으로 실행하기","description":"Agent SDK를 사용하여 CLI, Python 또는 TypeScript에서 Claude Code를 프로그래밍 방식으로 실행합니다.","frontmatter":{"title":"Claude Code 프로그래밍 방식으로 실행하기","description":"Agent SDK를 사용하여 CLI, Python 또는 TypeScript에서 Claude Code를 프로그래밍 방식으로 실행합니다."},"headers":[],"relativePath":"headless.md","filePath":"headless.md","lastUpdated":1776205703000}'),d={name:"headless.md"};function o(l,s,n,h,p,c){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="claude-code-프로그래밍-방식으로-실행하기" tabindex="-1">Claude Code 프로그래밍 방식으로 실행하기 <a class="header-anchor" href="#claude-code-프로그래밍-방식으로-실행하기" aria-label="Permalink to &quot;Claude Code 프로그래밍 방식으로 실행하기&quot;">​</a></h1><p><a href="/claude-code-docs-ko/agent-sdk/overview.html">Agent SDK</a>는 Claude Code를 구동하는 동일한 도구, 에이전트 루프, 컨텍스트 관리를 제공합니다. 스크립트 및 CI/CD용 CLI로 제공되거나, 완전한 프로그래밍 제어를 위한 <a href="/claude-code-docs-ko/agent-sdk/python.html">Python</a> 및 <a href="/claude-code-docs-ko/agent-sdk/typescript.html">TypeScript</a> 패키지로 제공됩니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>CLI는 이전에 &quot;headless mode&quot;로 불렸습니다. <code>-p</code> 플래그와 모든 CLI 옵션은 동일하게 작동합니다.</p></div><p>CLI에서 Claude Code를 프로그래밍 방식으로 실행하려면 <code>-p</code>와 프롬프트 및 <a href="/claude-code-docs-ko/cli-reference.html">CLI 옵션</a>을 전달하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Find and fix the bug in auth.py&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allowedTools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Read,Edit,Bash&quot;</span></span></code></pre></div><p>이 페이지는 CLI(<code>claude -p</code>)를 통한 Agent SDK 사용을 다룹니다. 구조화된 출력, 도구 승인 콜백, 네이티브 메시지 객체가 있는 Python 및 TypeScript SDK 패키지에 대해서는 <a href="/claude-code-docs-ko/agent-sdk/overview.html">전체 Agent SDK 문서</a>를 참조하세요.</p><h2 id="basic-usage" tabindex="-1">기본 사용법 <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;기본 사용법 {#basic-usage}&quot;">​</a></h2><p>모든 <code>claude</code> 명령에 <code>-p</code> (또는 <code>--print</code>) 플래그를 추가하여 비대화형으로 실행합니다. 모든 <a href="/claude-code-docs-ko/cli-reference.html">CLI 옵션</a>이 <code>-p</code>와 함께 작동하며, 다음을 포함합니다:</p><ul><li><code>--continue</code> - <a href="#continue-conversations">대화 이어가기</a></li><li><code>--allowedTools</code> - <a href="#auto-approve-tools">도구 자동 승인</a></li><li><code>--output-format</code> - <a href="#get-structured-output">구조화된 출력</a></li></ul><p>이 예제는 코드베이스에 대한 질문을 하고 응답을 출력합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;What does the auth module do?&quot;</span></span></code></pre></div><h3 id="start-faster-with-bare-mode" tabindex="-1">bare 모드로 더 빠르게 시작하기 <a class="header-anchor" href="#start-faster-with-bare-mode" aria-label="Permalink to &quot;bare 모드로 더 빠르게 시작하기 {#start-faster-with-bare-mode}&quot;">​</a></h3><p><code>--bare</code>를 추가하면 hooks, skills, 플러그인, MCP 서버, 자동 메모리, CLAUDE.md의 자동 검색을 건너뛰어 시작 시간을 줄입니다. 이 플래그가 없으면 <code>claude -p</code>는 대화형 세션과 동일한 <a href="/claude-code-docs-ko/how-claude-code-works.html#the-context-window">컨텍스트</a>를 로드하며, 작업 디렉토리나 <code>~/.claude</code>에 구성된 모든 것을 포함합니다.</p><p>bare 모드는 모든 머신에서 동일한 결과가 필요한 CI 및 스크립트에 유용합니다. 동료의 <code>~/.claude</code>에 있는 hook이나 프로젝트의 <code>.mcp.json</code>에 있는 MCP 서버는 실행되지 않습니다. bare 모드는 이를 읽지 않기 때문입니다. 명시적으로 전달한 플래그만 적용됩니다.</p><p>이 예제는 bare 모드에서 일회성 요약 작업을 실행하고 Read 도구를 사전 승인하여 권한 프롬프트 없이 호출을 완료합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bare</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Summarize this file&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --allowedTools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Read&quot;</span></span></code></pre></div><p>bare 모드에서 Claude는 Bash, 파일 읽기, 파일 편집 도구에 접근할 수 있습니다. 필요한 컨텍스트는 플래그로 전달하세요:</p><table tabindex="0"><thead><tr><th>로드할 항목</th><th>사용할 플래그</th></tr></thead><tbody><tr><td>시스템 프롬프트 추가</td><td><code>--append-system-prompt</code>, <code>--append-system-prompt-file</code></td></tr><tr><td>설정</td><td><code>--settings &lt;file-or-json&gt;</code></td></tr><tr><td>MCP 서버</td><td><code>--mcp-config &lt;file-or-json&gt;</code></td></tr><tr><td>커스텀 에이전트</td><td><code>--agents &lt;json&gt;</code></td></tr><tr><td>플러그인 디렉토리</td><td><code>--plugin-dir &lt;path&gt;</code></td></tr></tbody></table><p>bare 모드는 OAuth 및 키체인 읽기를 건너뜁니다. Anthropic 인증은 <code>ANTHROPIC_API_KEY</code> 또는 <code>--settings</code>에 전달된 JSON의 <code>apiKeyHelper</code>에서 가져와야 합니다. Bedrock, Vertex, Foundry는 일반적인 제공자 자격 증명을 사용합니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p><code>--bare</code>는 스크립트 및 SDK 호출에 권장되는 모드이며, 향후 릴리스에서 <code>-p</code>의 기본값이 될 예정입니다.</p></div><h2 id="examples" tabindex="-1">예제 <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;예제 {#examples}&quot;">​</a></h2><p>이 예제들은 일반적인 CLI 패턴을 보여줍니다. CI 및 기타 스크립트 호출의 경우, 로컬에 구성된 항목을 가져오지 않도록 <a href="#start-faster-with-bare-mode"><code>--bare</code></a>를 추가하세요.</p><h3 id="get-structured-output" tabindex="-1">구조화된 출력 받기 <a class="header-anchor" href="#get-structured-output" aria-label="Permalink to &quot;구조화된 출력 받기 {#get-structured-output}&quot;">​</a></h3><p><code>--output-format</code>을 사용하여 응답 반환 방식을 제어합니다:</p><ul><li><code>text</code> (기본값): 일반 텍스트 출력</li><li><code>json</code>: 결과, 세션 ID, 메타데이터가 포함된 구조화된 JSON</li><li><code>stream-json</code>: 실시간 스트리밍을 위한 개행 구분 JSON</li></ul><p>이 예제는 프로젝트 요약을 세션 메타데이터가 포함된 JSON으로 반환하며, 텍스트 결과는 <code>result</code> 필드에 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Summarize this project&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span></span></code></pre></div><p>특정 스키마에 맞는 출력을 얻으려면 <code>--output-format json</code>과 <code>--json-schema</code> 및 <a href="https://json-schema.org/" target="_blank" rel="noreferrer">JSON Schema</a> 정의를 함께 사용하세요. 응답에는 요청에 대한 메타데이터(세션 ID, 사용량 등)가 포함되며, 구조화된 출력은 <code>structured_output</code> 필드에 있습니다.</p><p>이 예제는 함수 이름을 추출하여 문자열 배열로 반환합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Extract the main function names from auth.py&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --json-schema</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;type&quot;:&quot;object&quot;,&quot;properties&quot;:{&quot;functions&quot;:{&quot;type&quot;:&quot;array&quot;,&quot;items&quot;:{&quot;type&quot;:&quot;string&quot;}}},&quot;required&quot;:[&quot;functions&quot;]}&#39;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">팁</p><p><a href="https://jqlang.github.io/jq/" target="_blank" rel="noreferrer">jq</a>와 같은 도구를 사용하여 응답을 파싱하고 특정 필드를 추출하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 텍스트 결과 추출</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Summarize this project&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.result&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 구조화된 출력 추출</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Extract function names from auth.py&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --json-schema</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;type&quot;:&quot;object&quot;,&quot;properties&quot;:{&quot;functions&quot;:{&quot;type&quot;:&quot;array&quot;,&quot;items&quot;:{&quot;type&quot;:&quot;string&quot;}}},&quot;required&quot;:[&quot;functions&quot;]}&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.structured_output&#39;</span></span></code></pre></div></div><h3 id="stream-responses" tabindex="-1">응답 스트리밍 <a class="header-anchor" href="#stream-responses" aria-label="Permalink to &quot;응답 스트리밍 {#stream-responses}&quot;">​</a></h3><p><code>--output-format stream-json</code>과 <code>--verbose</code> 및 <code>--include-partial-messages</code>를 사용하여 토큰이 생성될 때마다 수신합니다. 각 줄은 이벤트를 나타내는 JSON 객체입니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Explain recursion&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stream-json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --include-partial-messages</span></span></code></pre></div><p>다음 예제는 <a href="https://jqlang.github.io/jq/" target="_blank" rel="noreferrer">jq</a>를 사용하여 텍스트 델타를 필터링하고 스트리밍 텍스트만 표시합니다. <code>-r</code> 플래그는 원시 문자열(따옴표 없음)을 출력하고 <code>-j</code>는 개행 없이 연결하여 토큰이 연속적으로 스트리밍됩니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Write a poem&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stream-json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --include-partial-messages</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rj</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;select(.type == &quot;stream_event&quot; and .event.delta.type? == &quot;text_delta&quot;) | .event.delta.text&#39;</span></span></code></pre></div><p>API 요청이 재시도 가능한 오류로 실패하면, Claude Code는 재시도 전에 <code>system/api_retry</code> 이벤트를 발생시킵니다. 이를 사용하여 재시도 진행 상황을 표시하거나 커스텀 백오프 로직을 구현할 수 있습니다.</p><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>type</code></td><td><code>&quot;system&quot;</code></td><td>메시지 타입</td></tr><tr><td><code>subtype</code></td><td><code>&quot;api_retry&quot;</code></td><td>재시도 이벤트임을 식별</td></tr><tr><td><code>attempt</code></td><td>integer</td><td>현재 시도 번호, 1부터 시작</td></tr><tr><td><code>max_retries</code></td><td>integer</td><td>허용된 총 재시도 횟수</td></tr><tr><td><code>retry_delay_ms</code></td><td>integer</td><td>다음 시도까지의 밀리초</td></tr><tr><td><code>error_status</code></td><td>integer 또는 null</td><td>HTTP 상태 코드, HTTP 응답이 없는 연결 오류의 경우 <code>null</code></td></tr><tr><td><code>error</code></td><td>string</td><td>오류 카테고리: <code>authentication_failed</code>, <code>billing_error</code>, <code>rate_limit</code>, <code>invalid_request</code>, <code>server_error</code>, <code>max_output_tokens</code>, 또는 <code>unknown</code></td></tr><tr><td><code>uuid</code></td><td>string</td><td>고유 이벤트 식별자</td></tr><tr><td><code>session_id</code></td><td>string</td><td>이벤트가 속한 세션</td></tr></tbody></table><p>콜백과 메시지 객체를 사용한 프로그래밍 방식의 스트리밍은 Agent SDK 문서의 <a href="/claude-code-docs-ko/agent-sdk/streaming-output.html">실시간 응답 스트리밍</a>을 참조하세요.</p><h3 id="auto-approve-tools" tabindex="-1">도구 자동 승인 <a class="header-anchor" href="#auto-approve-tools" aria-label="Permalink to &quot;도구 자동 승인 {#auto-approve-tools}&quot;">​</a></h3><p><code>--allowedTools</code>를 사용하여 Claude가 프롬프트 없이 특정 도구를 사용할 수 있게 합니다. 이 예제는 테스트 스위트를 실행하고 실패를 수정하며, Claude가 권한 요청 없이 Bash 명령을 실행하고 파일을 읽고 편집할 수 있게 합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Run the test suite and fix any failures&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --allowedTools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Bash,Read,Edit&quot;</span></span></code></pre></div><p>개별 도구를 나열하는 대신 전체 세션의 기준을 설정하려면 <a href="/claude-code-docs-ko/permission-modes.html">권한 모드</a>를 전달하세요. <code>dontAsk</code>는 <code>permissions.allow</code> 규칙에 없는 모든 것을 거부하며, 잠금된 CI 실행에 유용합니다. <code>acceptEdits</code>는 Claude가 프롬프트 없이 파일을 작성하고 <code>mkdir</code>, <code>touch</code>, <code>mv</code>, <code>cp</code>와 같은 일반적인 파일시스템 명령도 자동 승인합니다. 다른 셸 명령과 네트워크 요청은 여전히 <code>--allowedTools</code> 항목이나 <code>permissions.allow</code> 규칙이 필요하며, 그렇지 않으면 시도 시 실행이 중단됩니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Apply the lint fixes&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --permission-mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> acceptEdits</span></span></code></pre></div><h3 id="create-a-commit" tabindex="-1">커밋 만들기 <a class="header-anchor" href="#create-a-commit" aria-label="Permalink to &quot;커밋 만들기 {#create-a-commit}&quot;">​</a></h3><p>이 예제는 스테이징된 변경 사항을 검토하고 적절한 메시지로 커밋을 생성합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Look at my staged changes and create an appropriate commit&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --allowedTools</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Bash(git diff *),Bash(git log *),Bash(git status *),Bash(git commit *)&quot;</span></span></code></pre></div><p><code>--allowedTools</code> 플래그는 <a href="/claude-code-docs-ko/settings.html#permission-rule-syntax">권한 규칙 구문</a>을 사용합니다. 뒤의 <code> *</code>는 접두사 매칭을 활성화하므로 <code>Bash(git diff *)</code>는 <code>git diff</code>로 시작하는 모든 명령을 허용합니다. <code>*</code> 앞의 공백이 중요합니다: 공백이 없으면 <code>Bash(git diff*)</code>는 <code>git diff-index</code>도 매칭합니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>사용자가 호출하는 <a href="/claude-code-docs-ko/skills.html">skills</a>(<code>/commit</code> 등)와 <a href="/claude-code-docs-ko/commands.html">내장 명령</a>은 대화형 모드에서만 사용할 수 있습니다. <code>-p</code> 모드에서는 수행하려는 작업을 설명하세요.</p></div><h3 id="customize-the-system-prompt" tabindex="-1">시스템 프롬프트 커스터마이즈 <a class="header-anchor" href="#customize-the-system-prompt" aria-label="Permalink to &quot;시스템 프롬프트 커스터마이즈 {#customize-the-system-prompt}&quot;">​</a></h3><p><code>--append-system-prompt</code>를 사용하여 Claude Code의 기본 동작을 유지하면서 지시사항을 추가합니다. 이 예제는 PR diff를 Claude에 파이프하고 보안 취약점을 검토하도록 지시합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --append-system-prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;You are a security engineer. Review for vulnerabilities.&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span></span></code></pre></div><p>기본 프롬프트를 완전히 교체하는 <code>--system-prompt</code>를 포함한 더 많은 옵션은 <a href="/claude-code-docs-ko/cli-reference.html#system-prompt-flags">시스템 프롬프트 플래그</a>를 참조하세요.</p><h3 id="continue-conversations" tabindex="-1">대화 이어가기 <a class="header-anchor" href="#continue-conversations" aria-label="Permalink to &quot;대화 이어가기 {#continue-conversations}&quot;">​</a></h3><p><code>--continue</code>를 사용하여 가장 최근 대화를 이어가거나, <code>--resume</code>과 세션 ID를 사용하여 특정 대화를 이어갑니다. 이 예제는 리뷰를 실행한 후 후속 프롬프트를 보냅니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 첫 번째 요청</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Review this codebase for performance issues&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 가장 최근 대화 이어가기</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Now focus on the database queries&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Generate a summary of all issues found&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span></span></code></pre></div><p>여러 대화를 실행하는 경우 세션 ID를 캡처하여 특정 대화를 재개합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">session_id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Start a review&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.session_id&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Continue that review&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resume</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$session_id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">다음 단계 <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;다음 단계 {#next-steps}&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/agent-sdk/quickstart.html">Agent SDK 퀵스타트</a>: Python 또는 TypeScript로 첫 번째 에이전트 빌드</li><li><a href="/claude-code-docs-ko/cli-reference.html">CLI 참조</a>: 모든 CLI 플래그 및 옵션</li><li><a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a>: GitHub 워크플로에서 Agent SDK 사용</li><li><a href="/claude-code-docs-ko/gitlab-ci-cd.html">GitLab CI/CD</a>: GitLab 파이프라인에서 Agent SDK 사용</li></ul>`,60)])])}const u=a(d,[["render",o]]);export{k as __pageData,u as default};
